package ir.tahamohamadi.blog.post; import ir.tahamohamadi.common.domain.LanguageCode; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*;
public interface BlogPostTranslationRepository extends JpaRepository<BlogPostTranslation,UUID>{ @Query("select t from BlogPostTranslation t join t.blogPost p where t.languageCode=:language and lower(t.slug)=lower(:slug) and t.deletedAt is null and p.deletedAt is null and p.status='PUBLISHED'") Optional<BlogPostTranslation> findPublishedByLanguageAndSlug(@Param("language") LanguageCode language,@Param("slug") String slug); @Query("select t from BlogPostTranslation t join t.blogPost p where t.languageCode=:language and t.deletedAt is null and p.deletedAt is null and p.status='PUBLISHED' order by p.publishedAt desc,p.id desc") List<BlogPostTranslation> findPublishedByLanguage(@Param("language") LanguageCode language,Pageable pageable); }
